function deepFieldSearch\($data, $searchTerms, $prefix = '', &$results = []\) {
    if \(!is_array\($data\)\) return $results;
    foreach \($data as $key => $value\) {
        $fullKey = $prefix ? "$prefix.$key" : $key;
        $lowerKey = strtolower\(\(string\)$key\);
